/**
 * PostToolUse hook: Auto-lint Python files after Edit/Write.
 *
 * Runs `uv run ruff check --fix`, `uv run ruff format`, and `uv run ty check` on .py files.
 * Skips migration files (auto-generated by Django).
 * Ruff failures stay silent (non-blocking). ty failures are surfaced to the
 * model on stderr without blocking, since the project rule is that ty must pass
 * before commit but type errors mid-edit are normal.
 *
 * Receives JSON on stdin: { tool_name, tool_input: { file_path, ... } }
 */
import { readFileSync } from 'node:fs'
import { execSync } from 'node:child_process'

const input = JSON.parse(readFileSync(0, 'utf8'))
const filePath = input.tool_input?.file_path

if (filePath && /\.py$/.test(filePath) && !/\/migrations\//.test(filePath.replace(/\\/g, '/'))) {
  try {
    execSync(`uv run ruff check --fix --quiet ${JSON.stringify(filePath)}`, { stdio: 'pipe' })
    execSync(`uv run ruff format --quiet ${JSON.stringify(filePath)}`, { stdio: 'pipe' })
  }
  catch {
    // Ruff errors are non-blocking
  }

  try {
    execSync(`uv run ty check ${JSON.stringify(filePath)}`, { stdio: 'pipe' })
  }
  catch (err) {
    // Surface ty errors to the model so they get fixed pre-commit, but never block.
    const out = (err.stdout?.toString() || '') + (err.stderr?.toString() || '')
    if (out.trim()) {
      process.stderr.write(`ty check found issues in ${filePath}:\n${out}`)
    }
  }
}
